const SURVIVAL_NEIGHBOR_COUNTS = [2, 3] as const;

export function nextGeneration(cells: Cell[]): Cell[] {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);
  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (isAlive(x + dx, y + dy)) count++;
      }
    }
    return count;
  };
  const survives = (x: number, y: number): boolean =>
    SURVIVAL_NEIGHBOR_COUNTS.includes(
      countNeighbors(x, y) as 2 | 3,
    );
  return cells.filter(([x, y]) => survives(x, y));
}

